/**
 * Task 1 — n8n Code Node: Tax Grid Scraper
 *
 * Paste this into an n8n "Code" node (mode: "Run Once for All Items").
 * No external npm packages needed — uses only Node built-ins.
 *
 * Output:
 *   items[0].json.taxGrid — Array<{ min, max, rate }>
 *
 * https://docs.n8n.io
 */

/* -------------------------------------------------------------------------- */
/*  Helpers (copied from scrape-tax-grid.js for self-contained n8n use)       */
/* -------------------------------------------------------------------------- */

async function fetchHtml(url) {
  return helpers.httpRequest({
    method: "GET",
    url,
    headers: { "User-Agent": "Mozilla/5.0" },
    returnFullResponse: false,
  });
}

function parseFrenchNumber(raw) {
  if (!raw) return null;
  const cleaned = raw
    .replace(/\u00A0/g, "")
    .replace(/\s/g, "")
    .replace(",", ".")
    .replace("%", "")
    .trim();
  const value = parseFloat(cleaned);
  return isNaN(value) ? null : value;
}

function stripTags(html) {
  return html
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, "\u00A0")
    .replace(/&amp;/g, "&")
    .replace(/\s+/g, " ")
    .trim();
}

function extractTableRows(html) {
  const sectionMarker =
    /Grille des taux par d.{1,10}faut applicables aux contribuables domicili.{1,5}s en m.{1,5}tropole/i;
  const markerIndex = html.search(sectionMarker);
  if (markerIndex === -1)
    throw new Error(
      "Target section not found — page structure may have changed.",
    );
  const relevantHtml = html.slice(markerIndex);
  const tableMatch = relevantHtml.match(/<table[\s\S]*?<\/table>/i);
  if (!tableMatch) throw new Error("No table found after target section.");
  return [...tableMatch[0].matchAll(/<tr[\s\S]*?<\/tr>/gi)].map((m) => m[0]);
}

function parseRangeText(text) {
  const parseAmt = (s) => parseFloat(s.replace(/[\s\u00A0]/g, '').replace(',', '.'));
  const supMatch = text.match(/sup.{1,10}rieure\s+ou\s+.{1,5}gale\s+[àa]\s+([\d\s\u00A0]+)\s*euros/i);
  const infMatch = text.match(/inf.{1,5}rieure\s+[àa]\s+([\d\s\u00A0]+)\s*euros/i);
  return {
    min: supMatch ? parseAmt(supMatch[1]) : 0,
    max: infMatch ? parseAmt(infMatch[1]) : null,
  };
}

function parseRows(rows) {
  const grid = [];
  for (const rowHtml of rows) {
    const cellMatches = [...rowHtml.matchAll(/<t[dh][\s\S]*?<\/t[dh]>/gi)];
    if (cellMatches.length < 2) continue;
    const cells = cellMatches.map((m) => stripTags(m[0]));
    const rate = parseFrenchNumber(cells[1]);
    if (rate === null) continue;
    const { min, max } = parseRangeText(cells[0]);
    grid.push({ min, max, rate: rate / 100 });
  }
  return grid;
}

/* -------------------------------------------------------------------------- */
/*  Main                                                                       */
/* -------------------------------------------------------------------------- */

const BOFIP_URL =
  "https://bofip.impots.gouv.fr/bofip/11255-PGP.html/identifiant%3DBOI-BAREME-000037-20250410";

const html = await fetchHtml(BOFIP_URL);
const rows = extractTableRows(html);
const taxGrid = parseRows(rows);

if (taxGrid.length === 0) {
  throw new Error("Parsed tax grid is empty — check BOFIP page structure.");
}

const netImposable = items[0].json.netImposable ?? null;
return [{ json: { taxGrid, scrapedAt: new Date().toISOString(), netImposable } }];

/**
 * Task 2 — n8n Code Node: Rate Comparator with Static State
 *
 * Paste this entire block into an n8n "Code" node (mode: "Run Once for All Items").
 *
 * Expected input items:
 *   items[0].json.netImposable  — number (monthly net imposable from PDF)
 *   items[0].json.taxGrid       — array from Task 1 scraper
 *                                 [{ min, max, rate }, ...]
 *
 * Workflow static data key: "lastAppliedRate"
 * Persists the last rate applied to impots.gouv.fr so we only trigger
 * the Playwright update when the bracket actually changes.
 */

/* -------------------------------------------------------------------------- */
/*  1. Read inputs                                                             */
/* -------------------------------------------------------------------------- */

const { netImposable, taxGrid } = items[0].json;

if (typeof netImposable !== 'number' || !Array.isArray(taxGrid)) {
  throw new Error(
    `Invalid input. Expected netImposable: number, taxGrid: array. Got: ${JSON.stringify({ netImposable, taxGrid })}`
  );
}

/* -------------------------------------------------------------------------- */
/*  2. Load persisted state                                                    */
/* -------------------------------------------------------------------------- */

/*
 * getWorkflowStaticData('global') persists across workflow executions.
 * It survives workflow re-saves and process restarts (stored in n8n DB).
 * Mutating the returned object automatically persists on node completion.
 */
const staticData = $getWorkflowStaticData('global');

const lastAppliedRate = staticData.lastAppliedRate ?? null;

/* -------------------------------------------------------------------------- */
/*  3. Find the matching bracket                                               */
/* -------------------------------------------------------------------------- */

/**
 * Finds the tax bracket for a given monthly income.
 * Brackets are half-open intervals: [min, max)
 * The last bracket has max === null (open-ended).
 */
function findBracket(income, grid) {
  for (const bracket of grid) {
    const withinMin = income >= bracket.min;
    const withinMax = bracket.max === null || income < bracket.max;

    if (withinMin && withinMax) {
      return bracket;
    }
  }
  return null;
}

const matchedBracket = findBracket(netImposable, taxGrid);

if (!matchedBracket) {
  throw new Error(
    `No bracket found for netImposable=${netImposable}. ` +
    `Grid range: ${taxGrid[0]?.min} – ${taxGrid[taxGrid.length - 1]?.max ?? '∞'}`
  );
}

const currentRate = matchedBracket.rate;

/* -------------------------------------------------------------------------- */
/*  4. Compare and decide                                                      */
/* -------------------------------------------------------------------------- */

const changeDetected = currentRate !== lastAppliedRate;

/* -------------------------------------------------------------------------- */
/*  5. Persist new rate if changed                                             */
/* -------------------------------------------------------------------------- */

if (changeDetected) {
  staticData.lastAppliedRate = currentRate;
}

/* -------------------------------------------------------------------------- */
/*  6. Return result to next node                                              */
/* -------------------------------------------------------------------------- */

/*
 * Downstream routing:
 *   IF node on changeDetected === true  → trigger Playwright script
 *   IF node on changeDetected === false → stop / notify "no change"
 */
return [
  {
    json: {
      changeDetected,
      currentRate,
      currentRatePercent: `${(currentRate * 100).toFixed(1)}%`,
      oldRate: lastAppliedRate,
      oldRatePercent: lastAppliedRate !== null ? `${(lastAppliedRate * 100).toFixed(1)}%` : null,
      netImposable,
      matchedBracket: {
        min: matchedBracket.min,
        max: matchedBracket.max,
        rate: matchedBracket.rate,
      },
      timestamp: new Date().toISOString(),
    },
  },
];

/**
 * Task 0b — n8n Code Node: Parse NET IMPOSABLE from PDF text
 *
 * Paste into a Code node (mode: "Run Once for All Items") after the Extract from File node.
 *
 * Input:  items[0].json.text — raw text extracted from the payslip PDF
 * Output: { netImposable: number }
 *
 * ⚠️ The regex may need tuning depending on the exact PDF format.
 *    Check the log output on first run to see the raw text.
 */

const text = items[0].json.text ?? '';

// Log a snippet to help debug if regex fails
console.log('PDF text (first 1000 chars):', text.slice(0, 1000));

// Target: "Impôt sur le revenu prélevé à la source <BASE> <taux> <montant>"
// The base (first number after the label) is the monthly net imposable for PAS
const match = text.match(/Imp.{1,5}t sur le revenu pr.{1,10}lev.{1,5}\s+[àa]\s+la source\s+([\d\s\u00A0]+[,]\d+)/i);

if (!match) {
  throw new Error('PAS base (Impôt sur le revenu prélevé à la source) not found in PDF. Check console log above for raw text.');
}

const raw = match[1].replace(/[\s\u00A0]/g, '').replace(',', '.');
const netImposable = parseFloat(raw);

if (isNaN(netImposable)) {
  throw new Error(`Failed to parse net imposable value from: "${match[1]}"`);
}

console.log('Parsed netImposable:', netImposable);

return [{ json: { netImposable } }];
